module PSRAMWrapper(
  input         clock,
                reset,
                io_in_psel,
                io_in_penable,
                io_in_pwrite,
  input  [31:0] io_in_paddr,
                io_in_pwdata,
  input  [3:0]  io_in_pstrb,
  output        io_in_pready,
  output [31:0] io_in_prdata,
  output        io_qspi_sck_o,
  output [2:0]  io_qspi_nss_o,
  output [3:0]  io_qspi_io_oe_o,
  input  [3:0]  io_qspi_io_di_i,
  output [3:0]  io_qspi_io_do_o
);

  wire        _npsram_nmi_ready;
  reg  [31:0] addrReg;
  reg  [31:0] wdataReg;
  reg  [3:0]  wstrbReg;
  reg         active;
  wire        setup = io_in_psel & ~io_in_penable;
  always @(posedge clock) begin
    if (~active & setup) begin
      addrReg <= {7'h20, io_in_paddr[24:2], 2'h0};
      wdataReg <= io_in_pwdata;
      wstrbReg <= io_in_pwrite ? io_in_pstrb : 4'h0;
    end
    if (reset)
      active <= 1'h0;
    else if (active)
      active <= ~_npsram_nmi_ready;
    else
      active <= setup;
  end // always @(posedge)
  `ifdef ENABLE_INITIAL_REG_
    `ifdef FIRRTL_BEFORE_INITIAL
      `FIRRTL_BEFORE_INITIAL
    `endif // FIRRTL_BEFORE_INITIAL
    logic [31:0] _RANDOM[0:2];
    initial begin
      `ifdef INIT_RANDOM_PROLOG_
        `INIT_RANDOM_PROLOG_
      `endif // INIT_RANDOM_PROLOG_
      `ifdef RANDOMIZE_REG_INIT
        for (logic [1:0] i = 2'h0; i < 2'h3; i += 2'h1) begin
          _RANDOM[i] = `RANDOM;
        end
        addrReg = _RANDOM[2'h0];
        wdataReg = _RANDOM[2'h1];
        wstrbReg = _RANDOM[2'h2][3:0];
        active = _RANDOM[2'h2][4];
      `endif // RANDOMIZE_REG_INIT
    end // initial
    `ifdef FIRRTL_AFTER_INITIAL
      `FIRRTL_AFTER_INITIAL
    `endif // FIRRTL_AFTER_INITIAL
  `endif // ENABLE_INITIAL_REG_
  nmi_psram #(
    .nss(3)
  ) npsram (
    .clk_i         (clock),
    .rst_n_i       (~reset),
    .nmi_valid     (active),
    .nmi_addr      (addrReg),
    .nmi_wdata     (wdataReg),
    .nmi_wstrb     (wstrbReg),
    .nmi_rdata     (io_in_prdata),
    .nmi_ready     (_npsram_nmi_ready),
    .psram_sck_o   (io_qspi_sck_o),
    .psram_nss_o   (io_qspi_nss_o),
    .psram_io_oe_o (io_qspi_io_oe_o),
    .psram_io_di_i (io_qspi_io_di_i),
    .psram_io_do_o (io_qspi_io_do_o),
    .psram_irq_o   (/* unused */)
  );
  assign io_in_pready = ~active | _npsram_nmi_ready;
endmodule

