// ----- 8< ----- FILE "./ESPWrapper.v" ----- 8< -----

module ESPWrapper #(
  parameter nss = 4
)(
  input sck_o,
  input [nss-1:0] nss_o,
  inout dio_0,
  inout dio_1,
  inout dio_2,
  inout dio_3
);
  ESP_PSRAM64H psram(
   .sclk(sck_o),
   .csn(nss_o[0]),
   .sio({dio_3, dio_2, dio_1, dio_0})  // bidirection for inout
 );
endmodule
    
